/**
 * Laravel CMS public API — same contract as compressedPDF-react.
 * Set VITE_SITE_DOMAIN to the domain registered in CMS → Domains (tenant).
 */

export function normalizeSiteDomain(value) {
  return String(value ?? '')
    .trim()
    .toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/:\d+$/, '')
    .split('/')[0]
}

const API_FALLBACK_DEV = 'http://localhost:8000'
/** Same Laravel host as compressedPDF-react — must serve `/api/public/*` JSON. */
const API_FALLBACK_PROD = 'https://app.apimstec.com'

export const CMS_API_BASE = String(
  import.meta.env.VITE_API_URL || (import.meta.env.DEV ? API_FALLBACK_DEV : API_FALLBACK_PROD),
).replace(/\/$/, '')

export const CMS_SITE_DOMAIN = normalizeSiteDomain(
  import.meta.env.VITE_SITE_DOMAIN || (import.meta.env.DEV ? 'localhost' : 'apimstec.com'),
)
