import { useMemo } from 'react'
import { Link, useLocation } from 'react-router-dom'
import { useTranslation } from '../i18n/useTranslation'
import { defaultLang } from '../i18n/translations'
import { buildApimstecBreadcrumbItems } from '../utils/breadcrumbTrail'
import './Breadcrumbs.css'

export default function Breadcrumbs() {
  const t = useTranslation(defaultLang)
  const location = useLocation()
  const items = useMemo(
    () => buildApimstecBreadcrumbItems(location.pathname, t),
    [location.pathname, t],
  )

  if (!items?.length) return null

  return (
    <nav className="site-breadcrumbs" aria-label="Breadcrumb">
      <ol className="site-breadcrumbs-list">
        {items.map((crumb, i) => {
          const last = i === items.length - 1
          return (
            <li key={`${crumb.label}-${i}-${crumb.to || ''}`} className="site-breadcrumbs-item">
              {last || !crumb.to ? (
                <span className="site-breadcrumbs-current" aria-current={last ? 'page' : undefined}>
                  {crumb.label}
                </span>
              ) : (
                <Link className="site-breadcrumbs-link" to={crumb.to}>
                  {crumb.label}
                </Link>
              )}
            </li>
          )
        })}
      </ol>
    </nav>
  )
}
