import { useEffect, useState, useMemo } from 'react'
import { useLocation } from 'react-router-dom'
import { SeoHead } from './SeoHead'
import { getHomeSeo } from '../api/cms'
import { defaultLang, langToOgLocale } from '../i18n/translations'
import { isCmsHomeSeoRoute } from '../utils/publicSeoRoutes'
import { buildLanguageAlternates, suffixFromPathname } from '../utils/hreflangForRoute'

const DEFAULT_SEO = {
  meta_title:       'ApimsTec | Technology, trust, and domain expertise',
  meta_description: 'ApimsTec delivers composable platforms, consultancy, and solutions for modern finance and digital transformation.',
  meta_keywords:    'ApimsTec, fintech, digital transformation, platform, consultancy, asset finance',
  focus_keyword:    'ApimsTec',
  og_title:         'ApimsTec',
  og_description:   'Composable technology and trusted expertise for lenders, OEMs, and enterprises.',
  og_image:         '/logos/apimstec-icon.svg',
  meta_robots:      'index,follow',
  canonical_url:    '',
}

/**
 * Loads CMS home SEO for the site home route only (`/`).
 * Page-level SeoHead in CmsPage/CmsBlog/Legal sets meta on detail routes.
 */
export default function DynamicSeoHead() {
  const [seoData, setSeoData] = useState(DEFAULT_SEO)
  const [loading, setLoading] = useState(true)
  const location = useLocation()

  const isHomeRoute = isCmsHomeSeoRoute(location.pathname)
  const locale = defaultLang

  const homeHreflangAlternates = useMemo(() => {
    if (typeof window === 'undefined') return null
    if (!isHomeRoute) return null
    const suffix = suffixFromPathname(location.pathname)
    return buildLanguageAlternates(window.location.origin, suffix)
  }, [isHomeRoute, location.pathname])

  useEffect(() => {
    if (!isHomeRoute) {
      setLoading(false)
      return undefined
    }

    let isMounted = true

    async function loadSeoData() {
      setLoading(true)
      try {
        const data = await getHomeSeo(locale, location.pathname)
        if (isMounted) {
          setSeoData({
            meta_title:       data.meta_title       || DEFAULT_SEO.meta_title,
            meta_description: data.meta_description || DEFAULT_SEO.meta_description,
            meta_keywords:    data.meta_keywords    || DEFAULT_SEO.meta_keywords,
            focus_keyword:    data.focus_keyword    || DEFAULT_SEO.focus_keyword,
            og_title:         data.og_title         || DEFAULT_SEO.og_title,
            og_description:   data.og_description   || DEFAULT_SEO.og_description,
            og_image:         data.og_image         || DEFAULT_SEO.og_image,
            meta_robots:      data.meta_robots      || DEFAULT_SEO.meta_robots,
            canonical_url:    data.canonical_url    || DEFAULT_SEO.canonical_url,
          })
        }
      } catch (error) {
        if (isMounted) setSeoData(DEFAULT_SEO)
      } finally {
        if (isMounted) setLoading(false)
      }
    }

    loadSeoData()
    return () => { isMounted = false }
  }, [isHomeRoute, locale, location.pathname])

  if (!isHomeRoute) {
    return null
  }

  if (loading) return null

  const robots =
    seoData.meta_robots && String(seoData.meta_robots).trim()
      ? String(seoData.meta_robots).trim()
      : 'index, follow'

  return (
    <SeoHead
      key={location.pathname}
      appendBrandSuffix={false}
      title={seoData.meta_title}
      description={seoData.meta_description}
      keywords={seoData.meta_keywords}
      robots={robots}
      canonical={seoData.canonical_url}
      ogTitle={seoData.og_title}
      ogDescription={seoData.og_description}
      ogImage={seoData.og_image}
      ogLocale={langToOgLocale(locale)}
      hreflangAlternates={homeHreflangAlternates}
    />
  )
}
